-- CMD-1.0 Wave B — mirror the 469 curated Airtable Tracking Companies into the spine.
-- Generated from Airtable base appxfti7VuoHYUeu6 / table tbluDYoK8Nj2DGQ0r (pulled 2026-07-23).
-- company_uid = 'cmp_'||substr(md5(name_normalized),1,16) — one canonical uid per normalized name.
-- Airtable is the editorial source of truth: identity -> companies columns; numeric/commercial/
-- leadership/energy -> company_facts (provenance). faraday_read mirrored verbatim, never generated.

-- Two additional raw-text attributes (Key Partnerships / Incumbent Link kept as sourced facts;
-- structured company_relationships extraction is deferred per STOP section 6 'propose only').
on conflict (attribute_code) do nothing;

drop table if exists public.stg_airtable_companies cascade;
create table public.stg_airtable_companies (
  rec_id text primary key, canonical_name text not null, name_normalized text,
  player_classification text, company_type text, entity_class text, ownership_public_private text,
  hq_location_raw text, ticker text, website_url text, linkedin_url text, nvidia_dsx_partner boolean,
  logo_url text, svg_logo_url text, svg_logo_hosted_url text, logo_lockup_url text, faraday_read text,
  ceo_name text, cfo_name text, cto_name text, annual_revenue_raw text, market_cap_raw text,
  capex_guided_raw text, total_funding_raised_raw text, employees_approx text,
  mw_total_airtable numeric, mw_live_airtable numeric, energy_strategy text, cooling_approach text,
  major_initiatives text, latest_faraday_signal text, key_partnerships_raw text, incumbent_link_raw text,
  idf_domains jsonb, source_name text, as_of date
);
alter table public.stg_airtable_companies enable row level security;
create policy cmd_stg_airt_service_only on public.stg_airtable_companies as restrictive for all to anon, authenticated using (false) with check (false);


update public.stg_airtable_companies set name_normalized = public.cmd_normalize_name(canonical_name);

   ownership_public_private, hq_location_raw, ticker, website_url, linkedin_url, nvidia_dsx_partner,
   logo_url, svg_logo_url, svg_logo_hosted_url, logo_lockup_url, faraday_read, identity_source, airtable_record_id)
select 'cmp_'||substr(md5(s.name_normalized),1,16), s.canonical_name, s.name_normalized, s.entity_class,
       s.player_classification, s.company_type, s.ownership_public_private, s.hq_location_raw, s.ticker,
       s.website_url, s.linkedin_url, s.nvidia_dsx_partner, s.logo_url, s.svg_logo_url, s.svg_logo_hosted_url,
       s.logo_lockup_url, s.faraday_read, 'airtable', s.rec_id
from (
  select distinct on (name_normalized) *
  from public.stg_airtable_companies where name_normalized is not null
  order by name_normalized,
    (case when player_classification is not null then 1 else 0 end
     + case when faraday_read is not null then 1 else 0 end
     + case when ticker is not null then 1 else 0 end
     + case when website_url is not null then 1 else 0 end
     + case when company_type is not null then 1 else 0 end) desc, rec_id
) s
on conflict (name_normalized) do nothing;

select 'cmp_'||substr(md5(s.name_normalized),1,16), s.canonical_name, s.name_normalized, 'airtable', 'exact', 1.0, true
from public.stg_airtable_companies s where s.name_normalized is not null
on conflict (company_uid, alias_normalized, alias_source) do nothing;

with c as (select s.*, 'cmp_'||substr(md5(s.name_normalized),1,16) uid from public.stg_airtable_companies s where s.name_normalized is not null)
select uid,'ceo_name',ceo_name,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where ceo_name is not null
union all
select uid,'cfo_name',cfo_name,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where cfo_name is not null
union all
select uid,'cto_name',cto_name,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where cto_name is not null
union all
select uid,'annual_revenue_raw',annual_revenue_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where annual_revenue_raw is not null
union all
select uid,'market_cap_raw',market_cap_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where market_cap_raw is not null
union all
select uid,'capex_guided_raw',capex_guided_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where capex_guided_raw is not null
union all
select uid,'total_funding_raised_raw',total_funding_raised_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where total_funding_raised_raw is not null
union all
select uid,'employees_approx',employees_approx,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where employees_approx is not null
union all
select uid,'power_sourcing_strategy',energy_strategy,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium','raw Airtable Energy Strategy; enum normalization deferred' from c where energy_strategy is not null
union all
select uid,'cooling_architecture',cooling_approach,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium','raw Airtable Cooling Approach; array normalization deferred' from c where cooling_approach is not null
union all
select uid,'major_initiatives',major_initiatives,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where major_initiatives is not null
union all
select uid,'latest_faraday_signal',latest_faraday_signal,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where latest_faraday_signal is not null
union all
select uid,'key_partnerships_raw',key_partnerships_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where key_partnerships_raw is not null
union all
select uid,'incumbent_link_raw',incumbent_link_raw,null::numeric,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where incumbent_link_raw is not null
union all
select uid,'mw_total_airtable',null::text,mw_total_airtable,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where mw_total_airtable is not null
union all
select uid,'mw_live_airtable',null::text,mw_live_airtable,null::boolean,null::date,null::jsonb,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where mw_live_airtable is not null
union all
select uid,'idf_domain_exposure',null::text,null::numeric,null::boolean,null::date,idf_domains,source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where idf_domains is not null
union all
select uid,'brand_assets',null::text,null::numeric,null::boolean,null::date,jsonb_strip_nulls(jsonb_build_object('logo_url',logo_url,'svg_logo_url',svg_logo_url,'svg_logo_hosted_url',svg_logo_hosted_url,'logo_lockup_url',logo_lockup_url)),source_name,'airtable',coalesce(as_of,'2026-07-23'::date),'medium',null from c where (coalesce(logo_url,svg_logo_url,svg_logo_hosted_url,logo_lockup_url) is not null)
on conflict (company_uid, attribute_code, as_of, source_name) do nothing;
